queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?category_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasOnline_News_Portals ?parent . } GROUP BY ?child }
  ?child p:category_name ?category_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Online_News_Portals } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?category_name WHERE {
  ?online_news_portals_categories a :Online_News_Portals_Categories .
  ?categories a :Category .
  ?online_news_portals_categories p:hasCategories ?categories .
  ?online_news_portals a :Online_News_Portals .
  ?online_news_portals_categories p:hasOnline_News_Portals ?online_news_portals .
  ?online_news_portals p:name ?name .
  ?categories p:category_name ?category_name .
} }
  collective: { SELECT ?category_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasOnline_News_Portals ?parent . } GROUP BY ?child }
  ?child p:category_name ?category_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Online_News_Portals } }
  FILTER(?nf = ?total)
} }
}
